section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "type": "object",
  "title": "agent-postmortem-template-output",
  "required": [
    "trace_id",
    "model_id",
    "incident_summary",
    "layer_attribution",
    "prompt_diff",
    "eval_delta",
    "replay_artefacts",
    "forbidden_seen"
  ],
  "properties": {
    "trace_id": {
      "description": "Unique trace identifier."
    },
    "model_id": {
      "description": "Provider/name-version."
    },
    "incident_summary": {
      "description": "\u2264200 chars."
    },
    "layer_attribution": {
      "description": "Exactly one."
    },
    "prompt_diff": {
      "description": "Byte-exact unified diff."
    },
    "eval_delta": {
      "description": "{before, after, target}."
    },
    "replay_artefacts": {
      "description": "Paths or trace links."
    },
    "trace_gaps": {
      "description": "Layers without replay artefact."
    },
    "forbidden_seen": {
      "description": "Forbidden patterns matched (must be empty)."
    }
  }
}
